    name = os.path.basename(fp)
    if any(k in name for k in ['add_condiment','select_fruit','select_book']):
        print('\n===== FILE', fp, '=====')
        txt = Path(fp).read_text()
        print(txt[:50000])

print('===== task-related configs containing benchmark names =====')
for root, dirs, files in os.walk('/opt/VLABench/VLABench/configs'):
    for fn in files:
        if fn.endswith(('.json','.yaml','.yml','.py')):
            fp=os.path.join(root,fn)
            try:
                txt=Path(fp).read_text(errors='ignore')
            except Exception:
                continue
            if any(k in txt for k in ['add_condiment','select_fruit','select_book']):
                print('\n===== CONFIG', fp, '=====')
                print(txt[:30000])

print('===== evaluator source =====')
try:
    from VLABench.evaluation.evaluator.base import Evaluator
    print(inspect.getsource(Evaluator)[:50000])
